+    fn selected_focused_item_has_highlight() {
+        let style = list_item_style(true, true);
+        // Selected + focused should have highlight background and bold
+        assert!(style.bg().is_some());
+        assert!(style.attrs().contains(StyleFlags::BOLD));
+    }
+
+    #[test]
